public void escape(Writer writer, String str) throws IOException {
    int len = str.length();
    for (int i = 0; i < len; i++) {
        char c = str.charAt(i);

        if (Character.isHighSurrogate(c) && i + 1 < len) {
            char low = str.charAt(i + 1);
